#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int p[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &p[i]);
        }
        int cards[n * m];
        for (int i = 0; i < n * m; i++) {
            cards[i] = i + 1;
        }
        int assigned_cards[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                assigned_cards[i][j] = -1;
            }
        }
        int card_index = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                assigned_cards[i][j] = cards[card_index];
                card_index++;
            }
        }
        int valid = 1;
        for (int i = 0; i < n; i++) {
            int wins = 0;
            for (int j = 0; j < m; j++) {
                if (assigned_cards[i][j] > assigned_cards[p[i]][j]) {
                    wins++;
                }
            }
            if (wins <= m / 2) {
                valid = 0;
                break;
            }
        }
        if (!valid) {
            printf("No Solution\n");
        } else {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    printf("%d ", assigned_cards[i][j]);
                }
                printf("\n");
            }
        }
    }
    return 0;
}

