            cards.push_back(i + 1);
        }
        int card_index = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                assigned_cards[i][j] = cards[card_index];
                card_index++;
            }
        }
        bool valid = true;
        for (int i = 0; i < n; i++) {
            int wins = 0;
            for (int j = 0; j < m; j++) {
                if (assigned_cards[i][j] > assigned_cards[p[i]][j]) {
                    wins++;
                }
            }
            if (wins <= m / 2) {
                valid = false;
                break;
            }
        }
        if (!valid) {
            cout << "No Solution" << endl;
        } else {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
