import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] p = new int[n];
            for (int i = 0; i < n; i++) {
                p[i] = sc.nextInt();
            }
            int[][] assigned_cards = new int[n][m];
            int[] cards = new int[n * m];
            for (int i = 0; i < n * m; i++) {
                cards[i] = i + 1;
            }
            int card_index = 0;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < m; j++) {
                    assigned_cards[i][j] = cards[card_index];
                    card_index++;
                }
            }
            boolean valid = true;
            for (int i = 0; i < n; i++) {
                int wins = 0;
                for (int j = 0; j < m; j++) {
                    if (assigned_cards[i][j] > assigned_cards[p[i]][j]) {
                        wins++;
                    }
                }
                if (wins <= m / 2) {
                    valid = false;
                    break;
                }
            }
            if (!valid) {
                System.out.println("No Solution");
            } else {
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < m; j++) {
